const MARCAS_INDEX = {};

const MARCAS_NOM010 = Object.keys(MARCAS_INDEX).sort();


const TIPOS_NOM010 = [...new Set(Object.values(DGN_CATALOG).map(d=>d.tipo).filter(Boolean))]

function getModelosDeMarca(marca){
  const dgns = MARCAS_INDEX[marca] || [];
  const seen = new Set();
  const result = [];
  for(const dgn of dgns){
    const data = DGN_CATALOG[dgn];
    for(const mo of (data.modelos||[])){
      const name = mo.m || mo;
      if(!seen.has(name)){
        seen.add(name);
        result.push({m: name, d: dgn, t: data.tipo||'', max: mo.max||'', e: mo.e||''});
      }
    }
  }
  return result;
}